// The previous attempt referenced `self`, `old(self)`, and treated
// `r1`/`r2` as PageTable values. In this synthetic det fn, `r1` and `r2`
// are unit `()`, and the two candidate post-states are the parameters
// `post1_self_` and `post2_self_`; the pre-state is `pre_self_`. Pull
// every ensures conjunct into the proof context for BOTH post-states so
// the two `forall`-bearing ensures get instantiated against matching
// PageTable instances and z3 can line up the per-conjunct equalities.

// --- Scalar fields ---------------------------------------------------
assert(post1_self_.kernel_l4_end == pre_self_.kernel_l4_end);
assert(post2_self_.kernel_l4_end == pre_self_.kernel_l4_end);
assert(post1_self_.kernel_l4_end == post2_self_.kernel_l4_end);

assert(post1_self_.pcid == pre_self_.pcid);
assert(post2_self_.pcid == pre_self_.pcid);
assert(post1_self_.pcid == post2_self_.pcid);

// --- Set-valued ensures (page_closure) -------------------------------
assert(post1_self_.page_closure() =~= pre_self_.page_closure().insert(page_map_ptr));
assert(post2_self_.page_closure() =~= pre_self_.page_closure().insert(page_map_ptr));
assert(post1_self_.page_closure() =~= post2_self_.page_closure());
assert(post1_self_.page_closure() == post2_self_.page_closure());

// --- Map-valued ensures (mapping_4k / 2m / 1g) -----------------------
assert(post1_self_.mapping_4k() =~= pre_self_.mapping_4k());
assert(post2_self_.mapping_4k() =~= pre_self_.mapping_4k());
assert(post1_self_.mapping_4k() =~= post2_self_.mapping_4k());
assert(post1_self_.mapping_4k() == post2_self_.mapping_4k());

assert(post1_self_.mapping_2m() =~= pre_self_.mapping_2m());
assert(post2_self_.mapping_2m() =~= pre_self_.mapping_2m());
assert(post1_self_.mapping_2m() =~= post2_self_.mapping_2m());
assert(post1_self_.mapping_2m() == post2_self_.mapping_2m());

assert(post1_self_.mapping_1g() =~= pre_self_.mapping_1g());
assert(post2_self_.mapping_1g() =~= pre_self_.mapping_1g());
assert(post1_self_.mapping_1g() =~= post2_self_.mapping_1g());
assert(post1_self_.mapping_1g() == post2_self_.mapping_1g());

// --- Seq-valued ensures (kernel_entries) -----------------------------
assert(post1_self_.kernel_entries =~= pre_self_.kernel_entries);
assert(post2_self_.kernel_entries =~= pre_self_.kernel_entries);
assert(post1_self_.kernel_entries =~= post2_self_.kernel_entries);
assert(post1_self_.kernel_entries == post2_self_.kernel_entries);

// --- Targeted spec_resolve_mapping_l4 facts --------------------------
assert(post1_self_.spec_resolve_mapping_l4(target_l4i).is_Some());
assert(post2_self_.spec_resolve_mapping_l4(target_l4i).is_Some());
assert(post1_self_.spec_resolve_mapping_l4(target_l4i).get_Some_0().addr == page_map_ptr);
assert(post2_self_.spec_resolve_mapping_l4(target_l4i).get_Some_0().addr == page_map_ptr);
assert(post1_self_.spec_resolve_mapping_l4(target_l4i).get_Some_0().addr
    == post2_self_.spec_resolve_mapping_l4(target_l4i).get_Some_0().addr);

// --- wf re-instantiation (forces wf-internal foralls to be matched
//     against the actual post-state instances of post1 and post2) ----
assert(post1_self_.wf());
assert(post2_self_.wf());
